import { useState, useEffect, useCallback, useRef } from "react";
import "./App.css";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:3001";

const VEHICLE_TYPES = [
  { label: "Car", icon: "🚗" },
  { label: "Truck", icon: "🚛" },
  { label: "Van", icon: "🚐" },
  { label: "Bike", icon: "🏍️" },
  { label: "Bus", icon: "🚌" },
  { label: "Other", icon: "🚙" },
];

// ── Helpers ───────────────────────────────────────────────────────
function calcTimeDiff(inTime, outTime) {
  if (!inTime || !outTime) return "";
  const diff = new Date(outTime) - new Date(inTime);
  if (diff < 0) return "Invalid";
  const h = Math.floor(diff / 3600000);
  const m = Math.floor((diff % 3600000) / 60000);
  return `${h}h ${m}m`;
}

function getTokenExpiry() {
  return parseInt(localStorage.getItem("tokenExpiry") || "0", 10);
}

function isTokenExpired() {
  return Date.now() >= getTokenExpiry();
}

function authHeaders() {
  return {
    "Content-Type": "application/json",
    Authorization: `Bearer ${localStorage.getItem("token")}`,
  };
}

// ── Eye Icon ──────────────────────────────────────────────────────
function EyeIcon({ visible }) {
  return visible ? (
    <svg
      width="18"
      height="18"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" />
      <circle cx="12" cy="12" r="3" />
    </svg>
  ) : (
    <svg
      width="18"
      height="18"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24" />
      <line x1="1" y1="1" x2="23" y2="23" />
    </svg>
  );
}

// ── Toast ─────────────────────────────────────────────────────────
function Toast({ toast }) {
  return (
    <div className={`toast ${toast.type}${toast.show ? " show" : ""}`}>
      <span>
        {toast.type === "success" ? "✓" : toast.type === "warn" ? "⚠" : "✕"}
      </span>
      <span>{toast.msg}</span>
    </div>
  );
}

// ── Modal Wrapper ─────────────────────────────────────────────────
function Modal({ title, onClose, children }) {
  useEffect(() => {
    const handler = (e) => {
      if (e.key === "Escape") onClose();
    };
    document.addEventListener("keydown", handler);
    return () => document.removeEventListener("keydown", handler);
  }, [onClose]);

  return (
    <div
      className="modal-backdrop"
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div className="modal-card">
        <div className="modal-header">
          <h2>{title}</h2>
          <button className="modal-close" onClick={onClose}>
            ✕
          </button>
        </div>
        <div className="modal-body">{children}</div>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
//  SESSION WARNING BANNER
// ════════════════════════════════════════════════════════════════════
function SessionWarning({ onRefresh, onLogout }) {
  return (
    <div className="session-warning">
      <span>⚠️ Your session expires in 5 minutes.</span>
      <button className="sw-btn-refresh" onClick={onRefresh}>
        Refresh Session
      </button>
      <button className="sw-btn-logout" onClick={onLogout}>
        Logout Now
      </button>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
//  LOGIN SCREEN
// ════════════════════════════════════════════════════════════════════
function LoginScreen({ onLogin, onGoRegister }) {
  const [form, setForm] = useState({ identifier: "", password: "" });
  const [showPwd, setShowPwd] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [toast, setToast] = useState({ show: false, msg: "", type: "error" });

  const showToast = (msg, type = "error") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  const validate = () => {
    const e = {};
    if (!form.identifier.trim()) e.identifier = "Email or username is required";
    if (!form.password) e.password = "Password is required";
    return e;
  };

  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/auth/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          identifier: form.identifier.trim(),
          password: form.password,
        }),
      });
      const data = await res.json();
      if (res.ok) {
        localStorage.setItem("token", data.token);
        localStorage.setItem("user", JSON.stringify(data.user));
        // Store expiry: 6 hours from now
        localStorage.setItem(
          "tokenExpiry",
          String(Date.now() + 6 * 60 * 60 * 1000),
        );
        onLogin(data.user);
      } else {
        showToast(data.message || "Login failed");
      }
    } catch {
      showToast("Could not connect to server.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-brand">
          <div className="auth-brand-icon">🚗</div>
          <h1 className="auth-title">
            Driver<span>Log</span>
          </h1>
          <p className="auth-subtitle">Fleet Management System</p>
        </div>
        <form onSubmit={handleSubmit} noValidate className="auth-form">
          <div className="auth-field">
            <label>Email or Username</label>
            <input
              type="text"
              name="identifier"
              value={form.identifier}
              onChange={handleChange}
              placeholder="Enter email or username"
              className={errors.identifier ? "error" : ""}
            />
            {errors.identifier && (
              <span className="err-msg">{errors.identifier}</span>
            )}
          </div>
          <div className="auth-field">
            <label>Password</label>
            <div className="pwd-wrap">
              <input
                type={showPwd ? "text" : "password"}
                name="password"
                value={form.password}
                onChange={handleChange}
                placeholder="Enter password"
                className={errors.password ? "error" : ""}
              />
              <button
                type="button"
                className="eye-btn"
                onClick={() => setShowPwd(!showPwd)}
              >
                <EyeIcon visible={showPwd} />
              </button>
            </div>
            {errors.password && (
              <span className="err-msg">{errors.password}</span>
            )}
          </div>
          <button
            type="submit"
            className={`auth-btn${loading ? " loading" : ""}`}
            disabled={loading}
          >
            {loading ? "Signing in…" : "Sign In"}
          </button>
        </form>
        <div className="auth-divider">
          <span>Don't have an account?</span>
        </div>
        <button className="auth-btn-outline" onClick={onGoRegister}>
          Create Account
        </button>
      </div>
      <Toast toast={toast} />
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
//  REGISTER SCREEN
// ════════════════════════════════════════════════════════════════════
function RegisterScreen({ onGoLogin }) {
  const [form, setForm] = useState({
    full_name: "",
    username: "",
    email: "",
    password: "",
    confirm_password: "",
  });
  const [show, setShow] = useState({
    password: false,
    confirm_password: false,
  });
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [toast, setToast] = useState({ show: false, msg: "", type: "success" });

  const showToast = (msg, type = "success") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  const validate = () => {
    const e = {};
    if (!form.full_name.trim()) e.full_name = "Full name is required";
    if (!form.username.trim()) e.username = "Username is required";
    else if (form.username.length < 3)
      e.username = "Username must be at least 3 characters";
    if (!form.email.trim()) e.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = "Enter a valid email";
    if (!form.password) e.password = "Password is required";
    else if (form.password.length < 6)
      e.password = "Password must be at least 6 characters";
    if (!form.confirm_password)
      e.confirm_password = "Please confirm your password";
    else if (form.password !== form.confirm_password)
      e.confirm_password = "Passwords do not match";
    return e;
  };

  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  };

  const toggleShow = (field) => setShow((s) => ({ ...s, [field]: !s[field] }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/auth/register`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          full_name: form.full_name.trim(),
          username: form.username.trim(),
          email: form.email.trim(),
          password: form.password,
        }),
      });
      const data = await res.json();
      if (res.ok) {
        showToast("Account created! Please sign in.", "success");
        setTimeout(() => onGoLogin(), 1800);
      } else {
        showToast(data.message || "Registration failed", "error");
      }
    } catch {
      showToast("Could not connect to server.", "error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card register-card">
        <div className="auth-brand">
          <div className="auth-brand-icon">🚗</div>
          <h1 className="auth-title">
            Create <span>Account</span>
          </h1>
          <p className="auth-subtitle">Join the Fleet Management System</p>
        </div>
        <form onSubmit={handleSubmit} noValidate className="auth-form">
          <div className="auth-grid-2">
            <div className="auth-field">
              <label>
                First & Last Name <span className="req">*</span>
              </label>
              <input
                type="text"
                name="full_name"
                value={form.full_name}
                onChange={handleChange}
                placeholder="e.g. Giri Patel"
                className={errors.full_name ? "error" : ""}
              />
              {errors.full_name && (
                <span className="err-msg">{errors.full_name}</span>
              )}
            </div>
            <div className="auth-field">
              <label>
                Username <span className="req">*</span>
              </label>
              <input
                type="text"
                name="username"
                value={form.username}
                onChange={handleChange}
                placeholder="e.g. giripatel"
                className={errors.username ? "error" : ""}
              />
              {errors.username && (
                <span className="err-msg">{errors.username}</span>
              )}
            </div>
          </div>
          <div className="auth-field">
            <label>
              Email <span className="req">*</span>
            </label>
            <input
              type="email"
              name="email"
              value={form.email}
              onChange={handleChange}
              placeholder="you@example.com"
              className={errors.email ? "error" : ""}
            />
            {errors.email && <span className="err-msg">{errors.email}</span>}
          </div>
          <div className="auth-field">
            <label>
              Password <span className="req">*</span>
            </label>
            <div className="pwd-wrap">
              <input
                type={show.password ? "text" : "password"}
                name="password"
                value={form.password}
                onChange={handleChange}
                placeholder="Min. 6 characters"
                className={errors.password ? "error" : ""}
              />
              <button
                type="button"
                className="eye-btn"
                onClick={() => toggleShow("password")}
              >
                <EyeIcon visible={show.password} />
              </button>
            </div>
            {errors.password && (
              <span className="err-msg">{errors.password}</span>
            )}
          </div>
          <div className="auth-field">
            <label>
              Confirm Password <span className="req">*</span>
            </label>
            <div className="pwd-wrap">
              <input
                type={show.confirm_password ? "text" : "password"}
                name="confirm_password"
                value={form.confirm_password}
                onChange={handleChange}
                placeholder="Re-enter password"
                className={errors.confirm_password ? "error" : ""}
              />
              <button
                type="button"
                className="eye-btn"
                onClick={() => toggleShow("confirm_password")}
              >
                <EyeIcon visible={show.confirm_password} />
              </button>
            </div>
            {errors.confirm_password && (
              <span className="err-msg">{errors.confirm_password}</span>
            )}
          </div>
          <button
            type="submit"
            className={`auth-btn${loading ? " loading" : ""}`}
            disabled={loading}
          >
            {loading ? "Creating Account…" : "Create Account"}
          </button>
        </form>
        <div className="auth-divider">
          <span>Already have an account?</span>
        </div>
        <button className="auth-btn-outline" onClick={onGoLogin}>
          Back to Sign In
        </button>
      </div>
      <Toast toast={toast} />
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
//  PROFILE MODAL
// ════════════════════════════════════════════════════════════════════
function ProfileModal({ user, onClose, onUpdated, onLogout }) {
  const [tab, setTab] = useState("info"); // "info" | "password"
  const [form, setForm] = useState({
    full_name: user.full_name || "",
    username: user.username || "",
    email: user.email || "",
  });
  const [pwd, setPwd] = useState({
    current_password: "",
    new_password: "",
    confirm_password: "",
  });
  const [show, setShow] = useState({
    current: false,
    new: false,
    confirm: false,
  });
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [toast, setToast] = useState({ show: false, msg: "", type: "success" });

  const showToast = (msg, type = "success") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  const handleInfoChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  };

  const handlePwdChange = (e) => {
    setPwd((f) => ({ ...f, [e.target.name]: e.target.value }));
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  };

  const validateInfo = () => {
    const e = {};
    if (!form.full_name.trim()) e.full_name = "Full name is required";
    if (!form.username.trim()) e.username = "Username is required";
    if (!form.email.trim()) e.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = "Enter a valid email";
    return e;
  };

  const validatePwd = () => {
    const e = {};
    if (!pwd.current_password)
      e.current_password = "Current password is required";
    if (!pwd.new_password) e.new_password = "New password is required";
    else if (pwd.new_password.length < 6) e.new_password = "Min. 6 characters";
    if (!pwd.confirm_password)
      e.confirm_password = "Please confirm new password";
    else if (pwd.new_password !== pwd.confirm_password)
      e.confirm_password = "Passwords do not match";
    return e;
  };

  const handleInfoSubmit = async (e) => {
    e.preventDefault();
    const errs = validateInfo();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/auth/me`, {
        method: "PUT",
        headers: authHeaders(),
        body: JSON.stringify({
          full_name: form.full_name.trim(),
          username: form.username.trim(),
          email: form.email.trim(),
        }),
      });
      const data = await res.json();
      if (res.status === 401) {
        onLogout();
        return;
      }
      if (res.ok) {
        const updatedUser = {
          ...user,
          full_name: data.user.full_name,
          username: data.user.username,
          email: data.user.email,
        };
        localStorage.setItem("user", JSON.stringify(updatedUser));
        if (data.token) {
          localStorage.setItem("token", data.token);
          localStorage.setItem(
            "tokenExpiry",
            String(Date.now() + 6 * 60 * 60 * 1000),
          );
        }
        onUpdated(updatedUser);
        showToast("Profile updated successfully!", "success");
      } else {
        showToast(data.message || "Update failed", "error");
      }
    } catch {
      showToast("Could not connect to server.", "error");
    } finally {
      setLoading(false);
    }
  };

  const handlePwdSubmit = async (e) => {
    e.preventDefault();
    const errs = validatePwd();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/auth/change-password`, {
        method: "PUT",
        headers: authHeaders(),
        body: JSON.stringify({
          current_password: pwd.current_password,
          new_password: pwd.new_password,
        }),
      });
      const data = await res.json();
      if (res.status === 401) {
        onLogout();
        return;
      }
      if (res.ok) {
        showToast("Password changed successfully!", "success");
        setPwd({
          current_password: "",
          new_password: "",
          confirm_password: "",
        });
      } else {
        showToast(data.message || "Failed to change password", "error");
      }
    } catch {
      showToast("Could not connect to server.", "error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal title="My Profile" onClose={onClose}>
      <div className="profile-tabs">
        <button
          className={`ptab${tab === "info" ? " active" : ""}`}
          onClick={() => setTab("info")}
        >
          👤 Profile Info
        </button>
        <button
          className={`ptab${tab === "password" ? " active" : ""}`}
          onClick={() => setTab("password")}
        >
          🔒 Change Password
        </button>
      </div>

      {tab === "info" && (
        <form onSubmit={handleInfoSubmit} noValidate className="auth-form">
          <div className="auth-field">
            <label>
              Full Name <span className="req">*</span>
            </label>
            <input
              type="text"
              name="full_name"
              value={form.full_name}
              onChange={handleInfoChange}
              placeholder="Full name"
              className={errors.full_name ? "error" : ""}
            />
            {errors.full_name && (
              <span className="err-msg">{errors.full_name}</span>
            )}
          </div>
          <div className="auth-field">
            <label>
              Username <span className="req">*</span>
            </label>
            <input
              type="text"
              name="username"
              value={form.username}
              onChange={handleInfoChange}
              placeholder="Username"
              className={errors.username ? "error" : ""}
            />
            {errors.username && (
              <span className="err-msg">{errors.username}</span>
            )}
          </div>
          <div className="auth-field">
            <label>
              Email <span className="req">*</span>
            </label>
            <input
              type="email"
              name="email"
              value={form.email}
              onChange={handleInfoChange}
              placeholder="Email"
              className={errors.email ? "error" : ""}
            />
            {errors.email && <span className="err-msg">{errors.email}</span>}
          </div>
          <button
            type="submit"
            className={`auth-btn${loading ? " loading" : ""}`}
            disabled={loading}
          >
            {loading ? "Saving…" : "Save Changes"}
          </button>
        </form>
      )}

      {tab === "password" && (
        <form onSubmit={handlePwdSubmit} noValidate className="auth-form">
          {["current_password", "new_password", "confirm_password"].map(
            (field, i) => (
              <div className="auth-field" key={field}>
                <label>
                  {
                    [
                      "Current Password",
                      "New Password",
                      "Confirm New Password",
                    ][i]
                  }{" "}
                  <span className="req">*</span>
                </label>
                <div className="pwd-wrap">
                  <input
                    type={
                      show[["current", "new", "confirm"][i]]
                        ? "text"
                        : "password"
                    }
                    name={field}
                    value={pwd[field]}
                    onChange={handlePwdChange}
                    placeholder={
                      [
                        "Enter current password",
                        "Min. 6 characters",
                        "Re-enter new password",
                      ][i]
                    }
                    className={errors[field] ? "error" : ""}
                  />
                  <button
                    type="button"
                    className="eye-btn"
                    onClick={() =>
                      setShow((s) => ({
                        ...s,
                        [["current", "new", "confirm"][i]]:
                          !s[["current", "new", "confirm"][i]],
                      }))
                    }
                  >
                    <EyeIcon visible={show[["current", "new", "confirm"][i]]} />
                  </button>
                </div>
                {errors[field] && (
                  <span className="err-msg">{errors[field]}</span>
                )}
              </div>
            ),
          )}
          <button
            type="submit"
            className={`auth-btn${loading ? " loading" : ""}`}
            disabled={loading}
          >
            {loading ? "Changing…" : "Change Password"}
          </button>
        </form>
      )}
      <Toast toast={toast} />
    </Modal>
  );
}

// ════════════════════════════════════════════════════════════════════
//  LOGS HISTORY MODAL
// ════════════════════════════════════════════════════════════════════
function LogsModal({ onClose, onLogout }) {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filterVehicle, setFilterVehicle] = useState("");
  const [editLog, setEditLog] = useState(null);
  const [toast, setToast] = useState({ show: false, msg: "", type: "success" });

  const showToast = (msg, type = "success") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  const fetchLogs = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/driver-log`, {
        headers: authHeaders(),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      const data = await res.json();
      setLogs(Array.isArray(data) ? data : []);
    } catch {
      showToast("Could not load logs.", "error");
    } finally {
      setLoading(false);
    }
  }, [onLogout]);

  useEffect(() => {
    fetchLogs();
  }, [fetchLogs]);

  const filtered = logs.filter((l) => {
    const s = search.toLowerCase();
    const matchSearch =
      !s ||
      l.DRIVER_NAME?.toLowerCase().includes(s) ||
      l.VEHICLE_NUMBER?.toLowerCase().includes(s) ||
      l.PURPOSE?.toLowerCase().includes(s);
    const matchVehicle = !filterVehicle || l.VEHICLE_TYPE === filterVehicle;
    return matchSearch && matchVehicle;
  });

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this log entry?")) return;
    try {
      const res = await fetch(`${API_URL}/api/driver-log/${id}`, {
        method: "DELETE",
        headers: authHeaders(),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      if (res.ok) {
        setLogs((l) => l.filter((x) => x.ID !== id));
        showToast("Log deleted.", "success");
      } else {
        showToast("Failed to delete.", "error");
      }
    } catch {
      showToast("Server error.", "error");
    }
  };

  const exportCSV = () => {
    const headers = [
      "Driver Name",
      "Purpose",
      "Vehicle Type",
      "Vehicle Number",
      "In Time",
      "Out Time",
      "Time Diff",
      "In KM",
      "Out KM",
      "KM Diff",
    ];
    const rows = filtered.map((l) => [
      l.DRIVER_NAME,
      l.PURPOSE,
      l.VEHICLE_TYPE,
      l.VEHICLE_NUMBER,
      new Date(l.IN_TIME).toLocaleString(),
      new Date(l.OUT_TIME).toLocaleString(),
      l.TIME_DIFFERENCE,
      l.IN_KM,
      l.OUT_KM,
      l.KM_DIFFERENCE,
    ]);
    const csv = [headers, ...rows]
      .map((r) => r.map((v) => `"${v ?? ""}"`).join(","))
      .join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `driver-logs-${Date.now()}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <Modal title="📋 Trip Log History" onClose={onClose}>
      <div className="logs-toolbar">
        <input
          className="logs-search"
          type="text"
          placeholder="🔍 Search driver, vehicle, purpose…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <select
          className="logs-filter"
          value={filterVehicle}
          onChange={(e) => setFilterVehicle(e.target.value)}
        >
          <option value="">All Vehicles</option>
          {VEHICLE_TYPES.map((v) => (
            <option key={v.label} value={v.label}>
              {v.icon} {v.label}
            </option>
          ))}
        </select>
        <button className="export-btn" onClick={exportCSV}>
          ⬇ Export CSV
        </button>
      </div>

      {loading ? (
        <div className="logs-loading">Loading logs…</div>
      ) : filtered.length === 0 ? (
        <div className="logs-empty">No logs found.</div>
      ) : (
        <div className="logs-table-wrap">
          <table className="logs-table">
            <thead>
              <tr>
                <th>Driver</th>
                <th>Purpose</th>
                <th>Vehicle</th>
                <th>Number</th>
                <th>In Time</th>
                <th>Out Time</th>
                <th>Duration</th>
                <th>KM</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((l) => (
                <tr key={l.ID}>
                  <td>
                    <strong>{l.DRIVER_NAME}</strong>
                  </td>
                  <td>{l.PURPOSE}</td>
                  <td>
                    {
                      VEHICLE_TYPES.find((v) => v.label === l.VEHICLE_TYPE)
                        ?.icon
                    }{" "}
                    {l.VEHICLE_TYPE}
                  </td>
                  <td>
                    <span className="vehicle-num-badge">
                      {l.VEHICLE_NUMBER}
                    </span>
                  </td>
                  <td>{new Date(l.IN_TIME).toLocaleString()}</td>
                  <td>{new Date(l.OUT_TIME).toLocaleString()}</td>
                  <td>
                    <span className="time-badge">{l.TIME_DIFFERENCE}</span>
                  </td>
                  <td>
                    <span className="km-badge">{l.KM_DIFFERENCE} km</span>
                  </td>
                  <td>
                    <div className="log-actions">
                      <button
                        className="edit-btn"
                        onClick={() => setEditLog(l)}
                        title="Edit"
                      >
                        ✏️
                      </button>
                      <button
                        className="del-btn"
                        onClick={() => handleDelete(l.ID)}
                        title="Delete"
                      >
                        🗑️
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      <div className="logs-count">
        {filtered.length} record{filtered.length !== 1 ? "s" : ""} shown
      </div>
      <Toast toast={toast} />

      {editLog && (
        <EditLogModal
          log={editLog}
          onClose={() => setEditLog(null)}
          onSaved={() => {
            setEditLog(null);
            fetchLogs();
            showToast("Log updated!", "success");
          }}
          onLogout={onLogout}
        />
      )}
    </Modal>
  );
}

// ════════════════════════════════════════════════════════════════════
//  EDIT LOG MODAL
// ════════════════════════════════════════════════════════════════════
function EditLogModal({ log, onClose, onSaved, onLogout }) {
  const toLocalDatetime = (dt) => {
    if (!dt) return "";
    const d = new Date(dt);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().slice(0, 16);
  };

  const [form, setForm] = useState({
    driverName: log.DRIVER_NAME || "",
    purpose: log.PURPOSE || "",
    vehicleType: log.VEHICLE_TYPE || "",
    vehicleNumber: log.VEHICLE_NUMBER || "",
    inTime: toLocalDatetime(log.IN_TIME),
    outTime: toLocalDatetime(log.OUT_TIME),
    inKm: log.IN_KM ?? "",
    outKm: log.OUT_KM ?? "",
  });
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const timeDiff = calcTimeDiff(form.inTime, form.outTime);
  const kmDiff = parseFloat(form.outKm) - parseFloat(form.inKm);

  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  };

  const validate = () => {
    const e = {};
    if (!form.driverName.trim()) e.driverName = "Required";
    if (!form.purpose.trim()) e.purpose = "Required";
    if (!form.vehicleType) e.vehicleType = "Required";
    if (!form.vehicleNumber.trim()) e.vehicleNumber = "Required";
    if (!form.inTime) e.inTime = "Required";
    if (!form.outTime) e.outTime = "Required";
    if (
      form.inTime &&
      form.outTime &&
      new Date(form.outTime) <= new Date(form.inTime)
    )
      e.outTime = "Must be after In Time";
    if (!form.inKm) e.inKm = "Required";
    if (!form.outKm) e.outKm = "Required";
    if (
      form.inKm &&
      form.outKm &&
      parseFloat(form.outKm) < parseFloat(form.inKm)
    )
      e.outKm = "Must be ≥ In KM";
    return e;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/api/driver-log/${log.ID}`, {
        method: "PUT",
        headers: authHeaders(),
        body: JSON.stringify({
          driver_name: form.driverName.trim(),
          purpose: form.purpose.trim(),
          vehicle_type: form.vehicleType,
          vehicle_number: form.vehicleNumber.trim().toUpperCase(),
          in_time: form.inTime,
          out_time: form.outTime,
          time_difference: timeDiff,
          in_km: parseFloat(form.inKm),
          out_km: parseFloat(form.outKm),
          km_difference: isNaN(kmDiff) ? 0 : parseFloat(kmDiff.toFixed(1)),
        }),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      if (res.ok) {
        onSaved();
      }
    } catch {
      console.error("Update failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal title="✏️ Edit Log Entry" onClose={onClose}>
      <form onSubmit={handleSubmit} noValidate className="auth-form">
        <div className="auth-grid-2">
          <div className="auth-field">
            <label>
              Driver Name <span className="req">*</span>
            </label>
            <input
              type="text"
              name="driverName"
              value={form.driverName}
              onChange={handleChange}
              className={errors.driverName ? "error" : ""}
            />
            {errors.driverName && (
              <span className="err-msg">{errors.driverName}</span>
            )}
          </div>
          <div className="auth-field">
            <label>
              Purpose <span className="req">*</span>
            </label>
            <input
              type="text"
              name="purpose"
              value={form.purpose}
              onChange={handleChange}
              className={errors.purpose ? "error" : ""}
            />
            {errors.purpose && (
              <span className="err-msg">{errors.purpose}</span>
            )}
          </div>
        </div>
        <div className="auth-field">
          <label>
            Vehicle Type <span className="req">*</span>
          </label>
          <div className="vehicle-options">
            {VEHICLE_TYPES.map((v) => (
              <div
                key={v.label}
                className={`vehicle-opt${form.vehicleType === v.label ? " selected" : ""}`}
                onClick={() => {
                  setForm((f) => ({ ...f, vehicleType: v.label }));
                  setErrors((err) => ({ ...err, vehicleType: "" }));
                }}
              >
                <span className="vicon">{v.icon}</span>
                {v.label}
              </div>
            ))}
          </div>
          {errors.vehicleType && (
            <span className="err-msg">{errors.vehicleType}</span>
          )}
        </div>
        <div className="auth-field">
          <label>
            Vehicle Number <span className="req">*</span>
          </label>
          <input
            type="text"
            name="vehicleNumber"
            value={form.vehicleNumber}
            onChange={handleChange}
            style={{ textTransform: "uppercase" }}
            className={errors.vehicleNumber ? "error" : ""}
          />
          {errors.vehicleNumber && (
            <span className="err-msg">{errors.vehicleNumber}</span>
          )}
        </div>
        <div className="auth-grid-2">
          <div className="auth-field">
            <label>
              In Time <span className="req">*</span>
            </label>
            <input
              type="datetime-local"
              name="inTime"
              value={form.inTime}
              onChange={handleChange}
              className={errors.inTime ? "error" : ""}
            />
            {errors.inTime && <span className="err-msg">{errors.inTime}</span>}
          </div>
          <div className="auth-field">
            <label>
              Out Time <span className="req">*</span>
            </label>
            <input
              type="datetime-local"
              name="outTime"
              value={form.outTime}
              onChange={handleChange}
              className={errors.outTime ? "error" : ""}
            />
            {errors.outTime && (
              <span className="err-msg">{errors.outTime}</span>
            )}
          </div>
          <div className="auth-field">
            <label>
              In KM <span className="req">*</span>
            </label>
            <input
              type="number"
              name="inKm"
              value={form.inKm}
              onChange={handleChange}
              min="0"
              className={errors.inKm ? "error" : ""}
            />
            {errors.inKm && <span className="err-msg">{errors.inKm}</span>}
          </div>
          <div className="auth-field">
            <label>
              Out KM <span className="req">*</span>
            </label>
            <input
              type="number"
              name="outKm"
              value={form.outKm}
              onChange={handleChange}
              min="0"
              className={errors.outKm ? "error" : ""}
            />
            {errors.outKm && <span className="err-msg">{errors.outKm}</span>}
          </div>
        </div>
        <div style={{ display: "flex", gap: "0.75rem" }}>
          <button
            type="button"
            className="auth-btn-outline"
            onClick={onClose}
            style={{ flex: 1 }}
          >
            Cancel
          </button>
          <button
            type="submit"
            className={`auth-btn${loading ? " loading" : ""}`}
            style={{ flex: 2 }}
            disabled={loading}
          >
            {loading ? "Saving…" : "Save Changes"}
          </button>
        </div>
      </form>
    </Modal>
  );
}

// ════════════════════════════════════════════════════════════════════
//  DASHBOARD STATS BAR
// ════════════════════════════════════════════════════════════════════
function StatsBar({ onLogout }) {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch(`${API_URL}/api/driver-log/stats`, {
          headers: authHeaders(),
        });
        if (res.status === 401) {
          onLogout();
          return;
        }
        if (res.ok) setStats(await res.json());
      } catch {
        /* silent */
      }
    };
    fetchStats();
  }, [onLogout]);

  if (!stats) return null;

  return (
    <div className="stats-bar">
      <div className="stat-card">
        <div className="stat-icon">📋</div>
        <div className="stat-info">
          <div className="stat-val">{stats.total_logs}</div>
          <div className="stat-label">Total Logs</div>
        </div>
      </div>
      <div className="stat-card">
        <div className="stat-icon">📅</div>
        <div className="stat-info">
          <div className="stat-val">{stats.logs_today}</div>
          <div className="stat-label">Today's Trips</div>
        </div>
      </div>
      <div className="stat-card">
        <div className="stat-icon">🛣️</div>
        <div className="stat-info">
          <div className="stat-val">{stats.total_km?.toLocaleString()} km</div>
          <div className="stat-label">Total Distance</div>
        </div>
      </div>
      <div className="stat-card">
        <div className="stat-icon">🚗</div>
        <div className="stat-info">
          <div className="stat-val">{stats.top_driver || "—"}</div>
          <div className="stat-label">Top Driver</div>
        </div>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
//  DRIVER LOG SCREEN
// ════════════════════════════════════════════════════════════════════
function DriverLogScreen({ user, onLogout, onUserUpdate }) {
  const [dark, setDark] = useState(false);
  const [form, setForm] = useState({
    driverName: "",
    purpose: "",
    vehicleType: "",
    vehicleNumber: "",
    inTime: "",
    outTime: "",
    inKm: "",
    outKm: "",
  });
  const [timeDiff, setTimeDiff] = useState("");
  const [kmDiff, setKmDiff] = useState("");
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState({ show: false, msg: "", type: "success" });
  const [errors, setErrors] = useState({});
  const [showProfile, setShowProfile] = useState(false);
  const [showLogs, setShowLogs] = useState(false);
  const [showSessionWarn, setShowSessionWarn] = useState(false);
  const sessionCheckRef = useRef(null);

  // ── JWT Expiry Monitoring ────────────────────────────────────────
  useEffect(() => {
    const check = () => {
      if (isTokenExpired()) {
        clearInterval(sessionCheckRef.current);
        showToast("Your session expired. Please sign in again.", "error");
        setTimeout(() => onLogout(), 2000);
        return;
      }
      // Warn if < 5 min left
      const remaining = getTokenExpiry() - Date.now();
      if (remaining < 5 * 60 * 1000 && remaining > 0) {
        setShowSessionWarn(true);
      } else {
        setShowSessionWarn(false);
      }
    };
    check();
    sessionCheckRef.current = setInterval(check, 60 * 1000); // check every 60s
    return () => clearInterval(sessionCheckRef.current);
  }, [onLogout]);

  const handleRefreshSession = async () => {
    try {
      const res = await fetch(`${API_URL}/api/auth/refresh`, {
        method: "POST",
        headers: authHeaders(),
      });
      if (res.ok) {
        const data = await res.json();
        localStorage.setItem("token", data.token);
        localStorage.setItem(
          "tokenExpiry",
          String(Date.now() + 6 * 60 * 60 * 1000),
        );
        setShowSessionWarn(false);
        showToast("Session refreshed!", "success");
      } else {
        onLogout();
      }
    } catch {
      onLogout();
    }
  };

  useEffect(() => {
    document.body.className = dark ? "dark" : "";
  }, [dark]);
  useEffect(() => {
    setTimeDiff(calcTimeDiff(form.inTime, form.outTime));
  }, [form.inTime, form.outTime]);
  useEffect(() => {
    const diff = parseFloat(form.outKm) - parseFloat(form.inKm);
    setKmDiff(!isNaN(diff) && diff >= 0 ? diff.toFixed(1) + " km" : "");
  }, [form.inKm, form.outKm]);

  const showToast = (msg, type = "success") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  const validate = () => {
    const e = {};
    if (!form.driverName.trim()) e.driverName = "Required";
    if (!form.purpose.trim()) e.purpose = "Required";
    if (!form.vehicleType) e.vehicleType = "Select a vehicle type";
    if (!form.vehicleNumber.trim()) e.vehicleNumber = "Required";
    if (!form.inTime) e.inTime = "Required";
    if (!form.outTime) e.outTime = "Required";
    if (
      form.inTime &&
      form.outTime &&
      new Date(form.outTime) <= new Date(form.inTime)
    )
      e.outTime = "Must be after In Time";
    if (!form.inKm) e.inKm = "Required";
    if (!form.outKm) e.outKm = "Required";
    if (
      form.inKm &&
      form.outKm &&
      parseFloat(form.outKm) < parseFloat(form.inKm)
    )
      e.outKm = "Must be ≥ In KM";
    return e;
  };

  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  };

  const handleVehicle = (v) => {
    setForm((f) => ({ ...f, vehicleType: v }));
    setErrors((err) => ({ ...err, vehicleType: "" }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (isTokenExpired()) {
      onLogout();
      return;
    }
    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }
    setLoading(true);
    try {
      const payload = {
        driver_name: form.driverName.trim(),
        purpose: form.purpose.trim(),
        vehicle_type: form.vehicleType,
        vehicle_number: form.vehicleNumber.trim().toUpperCase(),
        in_time: form.inTime,
        out_time: form.outTime,
        time_difference: timeDiff,
        in_km: parseFloat(form.inKm),
        out_km: parseFloat(form.outKm),
        km_difference: parseFloat(
          (parseFloat(form.outKm) - parseFloat(form.inKm)).toFixed(1),
        ),
      };
      const res = await fetch(`${API_URL}/api/driver-log`, {
        method: "POST",
        headers: authHeaders(),
        body: JSON.stringify(payload),
      });
      if (res.status === 401) {
        onLogout();
        return;
      }
      const data = await res.json();
      if (res.ok) {
        showToast("Driver log saved successfully!", "success");
        setForm({
          driverName: "",
          purpose: "",
          vehicleType: "",
          vehicleNumber: "",
          inTime: "",
          outTime: "",
          inKm: "",
          outKm: "",
        });
        setTimeDiff("");
        setKmDiff("");
        setErrors({});
      } else {
        showToast(data.message || "Server error", "error");
      }
    } catch {
      showToast("Could not connect to server.", "error");
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    localStorage.removeItem("tokenExpiry");
    onLogout();
  };

  return (
    <div className="app">
      {showSessionWarn && (
        <SessionWarning
          onRefresh={handleRefreshSession}
          onLogout={handleLogout}
        />
      )}

      <div className="header">
        <div className="header-left">
          <div className="eyebrow">Fleet Management</div>
          <h1 className="title">
            Driver <span>Log</span>
          </h1>
          <p className="subtitle">
            Record vehicle trips and track mileage in real-time
          </p>
        </div>
        <div className="header-right">
          <button className="logs-nav-btn" onClick={() => setShowLogs(true)}>
            📋 View Logs
          </button>
          <button className="theme-btn" onClick={() => setDark(!dark)}>
            <span>{dark ? "☀️" : "🌙"}</span>
            <span>{dark ? "Light" : "Dark"}</span>
          </button>
          <div
            className="user-info"
            onClick={() => setShowProfile(true)}
            title="Edit Profile"
            style={{ cursor: "pointer" }}
          >
            <span className="user-avatar">
              {user?.full_name?.charAt(0).toUpperCase()}
            </span>
            <span className="user-name">{user?.full_name}</span>
            <span className="edit-profile-hint">✏️</span>
          </div>
          <button className="logout-btn" onClick={handleLogout}>
            Sign Out
          </button>
        </div>
      </div>

      <StatsBar onLogout={handleLogout} />

      <form onSubmit={handleSubmit} noValidate>
        <div className="card">
          <div className="section-label">Driver Information</div>
          <div className="grid-2">
            <div className="field full">
              <label>
                Driver Name <span className="req">*</span>
              </label>
              <input
                type="text"
                name="driverName"
                value={form.driverName}
                onChange={handleChange}
                placeholder="Enter full name"
                className={errors.driverName ? "error" : ""}
              />
              {errors.driverName && (
                <span className="err-msg">{errors.driverName}</span>
              )}
            </div>
            <div className="field full">
              <label>
                Purpose of Trip <span className="req">*</span>
              </label>
              <input
                type="text"
                name="purpose"
                value={form.purpose}
                onChange={handleChange}
                placeholder="e.g. Client Visit, Delivery…"
                className={errors.purpose ? "error" : ""}
              />
              {errors.purpose && (
                <span className="err-msg">{errors.purpose}</span>
              )}
            </div>
          </div>
        </div>

        <div className="card">
          <div className="section-label">Vehicle Details</div>
          <div className="field">
            <label>
              Vehicle Type <span className="req">*</span>
            </label>
            <div className="vehicle-options">
              {VEHICLE_TYPES.map((v) => (
                <div
                  key={v.label}
                  className={`vehicle-opt${form.vehicleType === v.label ? " selected" : ""}`}
                  onClick={() => handleVehicle(v.label)}
                >
                  <span className="vicon">{v.icon}</span>
                  {v.label}
                </div>
              ))}
            </div>
            {errors.vehicleType && (
              <span className="err-msg">{errors.vehicleType}</span>
            )}
          </div>
          <div className="field" style={{ marginTop: "1rem" }}>
            <label>
              Vehicle Number <span className="req">*</span>
            </label>
            <input
              type="text"
              name="vehicleNumber"
              value={form.vehicleNumber}
              onChange={handleChange}
              placeholder="e.g. GJ05AB1234"
              className={errors.vehicleNumber ? "error" : ""}
              style={{ textTransform: "uppercase" }}
            />
            {errors.vehicleNumber && (
              <span className="err-msg">{errors.vehicleNumber}</span>
            )}
          </div>
        </div>

        <div className="card">
          <div className="section-label">Trip Timing</div>
          <div className="grid-2">
            <div className="field">
              <label>
                In Time <span className="req">*</span>
              </label>
              <input
                type="datetime-local"
                name="inTime"
                value={form.inTime}
                onChange={handleChange}
                className={errors.inTime ? "error" : ""}
              />
              {errors.inTime && (
                <span className="err-msg">{errors.inTime}</span>
              )}
            </div>
            <div className="field">
              <label>
                Out Time <span className="req">*</span>
              </label>
              <input
                type="datetime-local"
                name="outTime"
                value={form.outTime}
                onChange={handleChange}
                className={errors.outTime ? "error" : ""}
              />
              {errors.outTime && (
                <span className="err-msg">{errors.outTime}</span>
              )}
            </div>
            <div className="field full">
              <label className="auto-label">
                <span>Time Difference</span>
                <span className="auto-badge">
                  <span className="auto-dot"></span>Auto-calculated
                </span>
              </label>
              <input
                type="text"
                value={timeDiff}
                readOnly
                className="readonly-field"
                placeholder="Will calculate automatically"
              />
            </div>
          </div>
        </div>

        <div className="card">
          <div className="section-label">Odometer Readings</div>
          <div className="grid-2">
            <div className="field">
              <label>
                In KM <span className="req">*</span>
              </label>
              <input
                type="number"
                name="inKm"
                value={form.inKm}
                onChange={handleChange}
                placeholder="0"
                min="0"
                className={errors.inKm ? "error" : ""}
              />
              {errors.inKm && <span className="err-msg">{errors.inKm}</span>}
            </div>
            <div className="field">
              <label>
                Out KM <span className="req">*</span>
              </label>
              <input
                type="number"
                name="outKm"
                value={form.outKm}
                onChange={handleChange}
                placeholder="0"
                min="0"
                className={errors.outKm ? "error" : ""}
              />
              {errors.outKm && <span className="err-msg">{errors.outKm}</span>}
            </div>
            <div className="field full">
              <label className="auto-label">
                <span>KM Difference</span>
                <span className="auto-badge">
                  <span className="auto-dot"></span>Auto-calculated
                </span>
              </label>
              <input
                type="text"
                value={kmDiff}
                readOnly
                className="readonly-field"
                placeholder="Will calculate automatically"
              />
            </div>
          </div>
        </div>

        <div className="card submit-card">
          <div className="submit-row">
            <p className="submit-info">
              Fields marked <span className="req">*</span> are required
            </p>
            <button
              type="submit"
              className={`submit-btn${loading ? " loading" : ""}`}
              disabled={loading}
            >
              <span>{loading ? "⟳" : "✓"}</span>
              <span>{loading ? "Submitting…" : "Submit Log"}</span>
            </button>
          </div>
        </div>
      </form>

      <Toast toast={toast} />

      {showProfile && (
        <ProfileModal
          user={user}
          onClose={() => setShowProfile(false)}
          onUpdated={(u) => {
            onUserUpdate(u);
            setShowProfile(false);
          }}
          onLogout={handleLogout}
        />
      )}
      {showLogs && (
        <LogsModal onClose={() => setShowLogs(false)} onLogout={handleLogout} />
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
//  ROOT APP
// ════════════════════════════════════════════════════════════════════
export default function App() {
  const [screen, setScreen] = useState("login");
  const [user, setUser] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const savedUser = localStorage.getItem("user");
    const expiry = getTokenExpiry();
    if (token && savedUser && Date.now() < expiry) {
      setUser(JSON.parse(savedUser));
      setScreen("app");
    } else {
      // Clear stale data
      localStorage.removeItem("token");
      localStorage.removeItem("user");
      localStorage.removeItem("tokenExpiry");
    }
  }, []);

  if (screen === "register")
    return <RegisterScreen onGoLogin={() => setScreen("login")} />;
  if (screen === "app")
    return (
      <DriverLogScreen
        user={user}
        onLogout={() => {
          setUser(null);
          setScreen("login");
        }}
        onUserUpdate={(u) => setUser(u)}
      />
    );
  return (
    <LoginScreen
      onLogin={(u) => {
        setUser(u);
        setScreen("app");
      }}
      onGoRegister={() => setScreen("register")}
    />
  );
}
